import sys
input = sys.stdin.readline

def solve():
    n = int(input())
    a = list(map(int, input().split()))

    # dp[rel_pos] = min spread
    dp = {0: 0}

    for ai in a:
        ndp = {}
        for r, s in dp.items():
            # go right
            nr = r + ai
            ns = max(s, nr)
            if nr not in ndp or ndp[nr] > ns:
                ndp[nr] = ns
            # go left
            if r >= ai:
                nr2 = r - ai
                ns2 = s
            else:
                nr2 = 0
                ns2 = s + (ai - r)
            if nr2 not in ndp or ndp[nr2] > ns2:
                ndp[nr2] = ns2
        dp = ndp

    print(min(dp.values()))

t = int(input())
for _ in range(t):
    solve()

